        dos.write(data);
        // 走你！
        dos.flush();

        // 读取来自服务端的消息
        System.out.println(dis.readUTF());

        // 完成，关闭socket。
        socket.close();

    }
}

import java.io.*;
import java.net.InetSocketAddress;
import java.net.ServerSocket;
import java.net.Socket;

public class UploadTCPServer {
    public static void main(String[] args) throws IOException {
        ServerSocket serverSocket = new ServerSocket();// 创建服务端套接字
        serverSocket.bind(new InetSocketAddress("127.0.0.1",10001),100);// 绑定地址
        System.out.println("服务端已启动");
        while (true){
            final Socket theSocket = serverSocket.accept(); // 循环获取客户端链接
            new Thread(new Runnable() {
                @Override
                public void run() {
                    try {
                        clientConnectionThread(theSocket);//在单独的线程中处理
                    }catch (Exception ex){
                        ex.printStackTrace();
                    }finally {
                        try {
                            theSocket.close(); // 确保socket关闭
                        } catch (IOException e) {
                            throw new RuntimeException(e);
                        }
                    }
                }
            }).start();
        }
    }

    public static void clientConnectionThread(Socket socket) throws IOException {
        // 获取发送流
        DataOutputStream dos = new DataOutputStream(socket.getOutputStream());
        // 获取接收流
        DataInputStream dis = new DataInputStream(socket.getInputStream());

        // 客户端的协议：首先上传一个int，代表文件的长度，随后上传文件的字节数据
        int fileLen = dis.readInt();
        // 直接创建一个文件一样大的缓冲区
        byte[] fileData = new byte[fileLen];
        // 读取文件数据
        dis.readFully(fileData);

        // 保存上传的文件
        // 首先创建目录
        File dir = new File("D:\\upload");
        if(!dir.exists()){
            dir.mkdirs();
        }
        // 创建要保存的文件
        FileOutputStream fos = new FileOutputStream(new File(dir,System.currentTimeMillis()+".jpg"));
        try{
            fos.write(fileData);
            fos.flush();
        }finally {
            fos.close();
        }


        // 发送回复
        dos.writeUTF("上传成功");
        dos.flush();
    }
}

import java.io.IOError;
import java.io.IOException;
import java.net.*;
import java.util.Scanner;

public class UDPClient {
    public static void main(String[] args) throws IOException {
        DatagramSocket datagramSocket = new DatagramSocket();
        System.out.println("请发送信息给服务器(localhost)");
        InetSocketAddress serverAddress = new InetSocketAddress("127.0.0.1",8000);
        Scanner scanner = new Scanner(System.in);
        while (true){
            System.out.print("请输入信息：");
            String s = scanner.nextLine();
            byte[] data = s.getBytes();
            DatagramPacket packet = new DatagramPacket(data,0,data.length);
            packet.setAddress(serverAddress.getAddress());
            packet.setPort(serverAddress.getPort());
            datagramSocket.send(packet);
        }
    }
}

import java.io.IOException;
import java.net.DatagramPacket;
import java.net.DatagramSocket;
import java.net.InetSocketAddress;
import java.net.SocketException;

public class UDPServer {
    public static void main(String[] args) throws IOException {
        System.out.println("这里是服务端，等待接收客户端信息。。。");
        DatagramSocket datagramSocket = new DatagramSocket(new InetSocketAddress("127.0.0.1",8000));
        // 创建接收缓冲区
        byte[] data = new byte[4096];
        DatagramPacket packet = new DatagramPacket(data,0,data.length);

        while (true){
            datagramSocket.receive(packet);
            int len = packet.getLength();
            String receivedData = new String(data,0,len);
            System.out.println("服务器已接收到消息："+receivedData);
        }
    }
}

